//! Orientation-as-spinor: live per-track 2pi-director / 4pi-sheet state + an audit-only admission
//! law. This makes the offline falsification analysis (docs/spinor-4pi-falsification.md) operational
//! inside the engine: as a confirmed track is matched frame to frame, we incrementally lift the
//! mod-pi silhouette director to a continuous angle, derive the half-angle spinor sheet sign, and
//! audit a closed rotation loop against the discrete double-cover law.
//!
//! WHAT THIS CERTIFIES (honest bounds). The silhouette principal axis (recon::describe.orientation)
//! is a HEADLESS director, defined mod-pi — an element of RP^1, a per-frame observable. The spinor
//! SHEET is NOT a per-frame observable; it is the half-angle lift of the track PATH (the
//! continuously accumulated winding of the director). This is exactly the theory's reading: "the
//! spinor is the lift." We recover the IN-PLANE U(1) sheet (the planar belt-trick / Dirac-string
//! restriction). The full SU(2) double cover — out-of-plane / SO(3) rotation, where 4pi is the
//! genuinely nontrivial statement — needs multi-view triangulation and stays ABSTAIN here; a single
//! silhouette cannot separate the rotation axis from foreshortening (docs §2.3). We assert the sheet
//! ONLY when the lift is unambiguous (Nyquist-passing step, well-defined axis); otherwise we abstain.
//!
//! Backing law: `Gnosis.OrientationSpinorBridge` (the discrete double cover — a `Fin 4` sheet-carrier
//! of order 4 upstairs / order 2 downstairs: the generator returns the director after 2 steps but
//! flips the sheet, returning the sheet only after 4) + docs/spinor-4pi-falsification.md §4.

use std::f32::consts::PI;

/// Below this elongation the principal axis is ill-defined (a round/blobby silhouette has no
/// director). docs §3 / recon.rs:60. The task asks the spinor be abstained below ~1.5; the offline
/// analysis used 2.0. We hold the looser live gate at 1.5 (reliability flag) and keep the stricter
/// 2.0 available for the loop audit precondition.
pub const ELONG_RELIABLE_MIN: f32 = 1.5;
/// The audit-loop precondition elongation (docs §3: "require elongation >= 2.0").
pub const ELONG_LOOP_MIN: f32 = 2.0;
/// Director Nyquist ceiling: a single inter-frame mod-pi step must fold to < pi/2, else the
/// minimal-step lift picks the wrong branch and the winding is aliased (docs §1.2).
pub const NYQUIST: f32 = PI / 2.0;

/// Fold a mod-pi director STEP to its minimal representative in (-pi/2, pi/2].
/// (The lift increment of docs §1.2.)
#[inline]
pub fn wrap_pi2(mut d: f32) -> f32 {
    while d <= -NYQUIST {
        d += PI;
    }
    while d > NYQUIST {
        d -= PI;
    }
    d
}

/// Sign of the half-angle spinor relative to the lift origin: s = sign(Re(exp(i * dchi))) where
/// dchi = (Theta - Theta_0) / 2. +1 on the start sheet, -1 on the antipodal sheet. This is the
/// continuously-tracked sqrt branch of the double-angle observable u = exp(2 i theta) (docs §1.3).
#[inline]
pub fn sheet_sign(director_unwrapped: f32, director_origin: f32) -> i8 {
    let dchi = 0.5 * (director_unwrapped - director_origin);
    if dchi.cos() >= 0.0 { 1 } else { -1 }
}

/// Incrementally-maintained orientation-spinor state for one confirmed track.
///
/// Updated once per matched step from the silhouette director. Holds the continuous director lift,
/// its winding, and the half-angle sheet sign — the live equivalent of the offline §5 protocol.
#[derive(Clone, Debug)]
pub struct OrientationSpinor {
    /// True once at least one director sample has been ingested.
    started: bool,
    /// The lift origin Theta_0 (first matched director), the sheet's reference phase.
    director_origin: f32,
    /// Previous matched mod-pi director (radians), for the minimal-step fold.
    prev_director: f32,
    /// Continuous lift of the mod-pi director (radians), accumulated minimal mod-pi steps.
    pub director_unwrapped: f32,
    /// Unwrapped arg(u) of the double-angle observable u = (cos 2theta, sin 2theta) — the
    /// single-valued measurement (docs §1.1). Winds twice per physical turn.
    pub argu_unwrapped: f32,
    /// Sign of the half-angle spinor sheet relative to the origin (+1/-1).
    pub sheet: i8,
    /// False (abstain) if any inter-frame director step exceeded Nyquist, or any matched sample had
    /// elongation below the reliability floor. Once false it stays false for the track: the lift is
    /// no longer trustworthy end to end.
    pub orientation_reliable: bool,
    /// Largest |folded step| seen (radians) — the Nyquist headroom (docs §5 step 8).
    pub max_step: f32,
    /// Smallest elongation seen across matched samples.
    pub min_elong: f32,
    /// Number of matched samples ingested.
    pub samples: u32,
    /// Number of sheet sign flips observed across the track.
    pub sheet_flips: u32,
    /// History of (director_unwrapped, argu_unwrapped, sheet) per matched sample, for loop audit.
    /// Capped to keep memory bounded on long tracks (the audit reads windings, not every sample).
    pub history: Vec<(f32, f32, i8)>,
}

const MAX_HISTORY: usize = 4096;

impl Default for OrientationSpinor {
    fn default() -> Self {
        OrientationSpinor {
            started: false,
            director_origin: 0.0,
            prev_director: 0.0,
            director_unwrapped: 0.0,
            argu_unwrapped: 0.0,
            sheet: 1,
            orientation_reliable: true,
            max_step: 0.0,
            min_elong: f32::INFINITY,
            samples: 0,
            sheet_flips: 0,
            history: Vec::new(),
        }
    }
}

impl OrientationSpinor {
    pub fn new() -> Self {
        Self::default()
    }

    /// Ingest one matched-frame director/elongation. `orientation` is the mod-pi silhouette director
    /// in [-pi/2, pi/2] (recon::describe); `elongation >= 1`. Maintains the lift, winding, sheet, and
    /// reliability incrementally (docs §5 steps 2-3-5, done live instead of offline).
    pub fn observe(&mut self, orientation: f32, elongation: f32) {
        self.min_elong = self.min_elong.min(elongation);
        if elongation < ELONG_RELIABLE_MIN {
            // Axis ill-defined this frame — the director (hence the lift) is untrustworthy.
            self.orientation_reliable = false;
        }

        if !self.started {
            self.started = true;
            self.director_origin = orientation;
            self.prev_director = orientation;
            self.director_unwrapped = orientation;
            self.argu_unwrapped = 2.0 * orientation;
            self.sheet = sheet_sign(self.director_unwrapped, self.director_origin);
            self.samples = 1;
            self.history.push((self.director_unwrapped, self.argu_unwrapped, self.sheet));
            return;
        }

        // Director lift: fold the mod-pi step to its minimal representative (docs §1.2).
        let step = wrap_pi2(orientation - self.prev_director);
        let astep = step.abs();
        self.max_step = self.max_step.max(astep);
        // Nyquist: a folded step at/over pi/2 means the true step was aliased — lift is ambiguous.
        if astep >= NYQUIST - 1e-6 {
            self.orientation_reliable = false;
        }
        self.director_unwrapped += step;
        self.prev_director = orientation;

        // Double-angle observable winding (single-valued; unwrap the 2theta increment over (-pi,pi]
        // relative to the running unwrapped arg — docs §1.1 / §5 step 2).
        let du = unwrap_2pi(2.0 * orientation - prev_arg_mod(self.argu_unwrapped));
        self.argu_unwrapped += du;

        let new_sheet = sheet_sign(self.director_unwrapped, self.director_origin);
        if new_sheet != self.sheet {
            self.sheet_flips += 1;
        }
        self.sheet = new_sheet;

        self.samples += 1;
        if self.history.len() < MAX_HISTORY {
            self.history.push((self.director_unwrapped, self.argu_unwrapped, self.sheet));
        }
    }

    /// Director winding number (in turns) accumulated over the whole track: Theta lift / 2pi.
    pub fn director_winding(&self) -> f32 {
        if !self.started {
            return 0.0;
        }
        (self.director_unwrapped - self.director_origin) / (2.0 * PI)
    }

    /// Observable winding number (in turns) of the double-angle vector u over the track.
    /// Winds twice per physical turn, so ~2x the director winding.
    pub fn observable_winding(&self) -> f32 {
        if self.history.is_empty() {
            return 0.0;
        }
        (self.argu_unwrapped - 2.0 * self.director_origin) / (2.0 * PI)
    }

    /// Run the audit-only admission law `orientation_spinor_periodicity` over the track's recorded
    /// loop. See [`SpinorVerdict`]. Audit signal only — never blocks tracking (docs §4).
    pub fn audit(&self) -> SpinorAudit {
        audit_loop(self)
    }
}

/// Reduce an unwrapped angle to its representative in (-pi, pi] relative to nothing — used to take
/// the difference between a new raw 2theta and the running unwrapped arg.
#[inline]
fn prev_arg_mod(argu_unwrapped: f32) -> f32 {
    let twopi = 2.0 * PI;
    let mut a = argu_unwrapped % twopi;
    if a <= -PI {
        a += twopi;
    }
    if a > PI {
        a -= twopi;
    }
    a
}

/// Fold an angle increment to (-pi, pi].
#[inline]
fn unwrap_2pi(mut d: f32) -> f32 {
    let twopi = 2.0 * PI;
    while d <= -PI {
        d += twopi;
    }
    while d > PI {
        d -= twopi;
    }
    d
}

/// The verdict of the audit-only orientation-spinor admission law (§7.5 style: accept / abstain /
/// decline + cited law). This NEVER blocks tracking; it is a per-track consistency signal.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum SpinorVerdict {
    /// Clauses (a)-(c) of `orientation_spinor_periodicity` hold over the loop with margin: the
    /// observable closes with even integer winding, the director winding is W_u/2, and the sheet
    /// parity equals director-winding mod 2 (sheet returns iff the director winding is even).
    Accept,
    /// Precondition unmet — the lift is unreliable (Nyquist aliasing / ill-defined axis) or the loop
    /// is incomplete (no full physical turn recorded). Held, not asserted (docs §4.2).
    Abstain,
    /// The law is violated on a clean loop: odd / non-integer observable winding, or the sheet parity
    /// disagrees with the director winding. The track most likely stitched two objects across an
    /// association error (docs §4.2): the "rotation" is an artifact, so the orientation fact is
    /// rejected.
    Decline,
}

/// Full audit report for a track loop — the live ledger row of docs §5 step 8.
#[derive(Clone, Debug)]
pub struct SpinorAudit {
    pub verdict: SpinorVerdict,
    /// Observable winding over the loop (turns); expect ~2 per physical turn.
    pub w_u: f32,
    /// Director winding over the loop (turns); expect ~1 per physical turn.
    pub w_dir: f32,
    /// Sheet sign at the first completed physical turn (2pi), if reached. Expect -start_sheet.
    pub sheet_at_2pi: Option<i8>,
    /// Sheet sign at the second completed physical turn (4pi), if reached. Expect +start_sheet.
    pub sheet_at_4pi: Option<i8>,
    /// Sheet sign flips over the audited span.
    pub sheet_flips: u32,
    pub max_step: f32,
    pub min_elong: f32,
    /// Human-readable cite + which clause decided the verdict.
    pub note: String,
}

const LAW: &str = "orientation_spinor_periodicity (Gnosis.OrientationSpinorBridge; docs/spinor-4pi-falsification.md §4)";

/// The admission law, run over an [`OrientationSpinor`]'s recorded path. Audit-only.
///
/// Clauses (docs §4.1):
///  (a) observable winding W_u is an even integer over a closed physical loop;
///  (b) director winding W_dir = W_u / 2 is an integer;
///  (c) sheet parity == W_dir mod 2 (sheet returns iff W_dir even) — the discrete double cover of
///      `Gnosis.OrientationSpinorBridge` (order 4 upstairs / order 2 downstairs).
pub fn audit_loop(sp: &OrientationSpinor) -> SpinorAudit {
    // Locate the physical-turn marks by unwrapped arg(u) advance (docs §5 step 4): one physical
    // turn = arg(u) advances by 4pi (u winds twice). We evaluate the law at the largest COMPLETED
    // integer number of physical turns, not at the ragged end of the clip — a 2.5-turn clip audits
    // its completed 2-turn loop, exactly the offline §2/§5 protocol (read the windings AT the loop
    // boundary). The post-loop tail (the extra 0.5 turn) is not part of any closed loop.
    let (theta0, argu0, sheet0) = sp.history.first().copied().unwrap_or((0.0, 0.0, 1));
    let (mut sheet_at_2pi, mut sheet_at_4pi) = (None, None);
    // Index + (theta,argu,sheet) of the last sample completing each whole physical turn.
    let mut loop_end: Option<(f32, f32, i8)> = None; // (theta,argu,sheet) at the last whole-turn mark
    let mut turns_seen = 0i64;
    for &(theta, argu, sheet) in &sp.history {
        let adv = (argu - argu0).abs();
        if sheet_at_2pi.is_none() && adv >= 4.0 * PI - 1e-3 {
            sheet_at_2pi = Some(sheet);
        }
        if sheet_at_4pi.is_none() && adv >= 8.0 * PI - 1e-3 {
            sheet_at_4pi = Some(sheet);
        }
        // adv / 4pi = number of physical turns elapsed; snapshot the FIRST sample crossing each new
        // whole-turn mark (so a 2.5-turn clip's loop boundary is the 2-turn mark, not the 2.5 tail).
        let turns_here = (adv / (4.0 * PI)).floor() as i64;
        if turns_here > turns_seen {
            turns_seen = turns_here;
            loop_end = Some((theta, argu, sheet));
        }
    }

    // Windings AT the loop boundary (or, if no full turn, over the whole ragged track for reporting).
    let (w_u, w_dir, end_sheet) = match loop_end {
        Some((theta_e, argu_e, sheet_e)) => (
            (argu_e - argu0) / (2.0 * PI),
            (theta_e - theta0) / (2.0 * PI),
            sheet_e,
        ),
        None => (sp.observable_winding(), sp.director_winding(), sp.sheet),
    };

    let mk = |verdict, note: &str| SpinorAudit {
        verdict,
        w_u,
        w_dir,
        sheet_at_2pi,
        sheet_at_4pi,
        sheet_flips: sp.sheet_flips,
        max_step: sp.max_step,
        min_elong: sp.min_elong,
        note: format!("{note} <- {LAW}"),
    };

    // Precondition: the lift must be reliable (Nyquist + well-defined axis). Aliasing / ill axis ->
    // ABSTAIN, never a verdict on the theory (docs §2.2 "Not a refutation", §4.2).
    if !sp.orientation_reliable {
        return mk(
            SpinorVerdict::Abstain,
            "lift unreliable (Nyquist aliasing or elongation below floor): held, not asserted",
        );
    }
    if sp.min_elong < ELONG_LOOP_MIN {
        return mk(
            SpinorVerdict::Abstain,
            "axis ill-conditioned for loop audit (elongation < 2.0): held, not asserted",
        );
    }

    // Need at least a full physical turn to decide anything.
    if sheet_at_2pi.is_none() {
        return mk(
            SpinorVerdict::Abstain,
            "no complete physical turn recorded (incomplete loop): held, not asserted",
        );
    }

    const TOL: f32 = 0.12;
    let nearest = |x: f32| (x.round(), (x - x.round()).abs());
    let (wu_round, wu_err) = nearest(w_u);
    let (wd_round, wd_err) = nearest(w_dir);

    // (a) observable winding even integer. On a closed physical loop u MUST close with integer
    // winding (it is single-valued); a non-integer or odd value on a Nyquist-passing, well-axised
    // loop is an internal estimator contradiction -> DECLINE (docs §4.2 R3).
    let wu_int = wu_err < TOL;
    let wu_even = ((wu_round as i64) % 2) == 0;
    if !wu_int || !wu_even {
        return mk(
            SpinorVerdict::Decline,
            "observable winding W_u not an even integer on a clean loop (estimator/association inconsistency)",
        );
    }

    // (b) director winding integer = W_u/2.
    let wd_int = wd_err < TOL;
    let wd_matches_half = (w_dir - w_u / 2.0).abs() < TOL;
    if !wd_int || !wd_matches_half {
        return mk(
            SpinorVerdict::Decline,
            "director winding W_dir not integer or != W_u/2 (director is not the RP^1 cover assumed)",
        );
    }

    // (c) sheet parity == W_dir mod 2 (the discrete double cover). The sheet returns iff the
    // director winding is even. Check the recorded sheet against the parity of the integer winding.
    let parity_even = ((wd_round as i64) % 2) == 0;
    let observed_returned = end_sheet == sheet0; // sheet relative to origin: returned == start sheet
    if parity_even != observed_returned {
        return mk(
            SpinorVerdict::Decline,
            "sheet parity disagrees with director-winding parity (likely two objects stitched into one track)",
        );
    }

    mk(
        SpinorVerdict::Accept,
        "closed-loop spinor periodicity holds: W_u even, W_dir=W_u/2, sheet parity = W_dir mod 2",
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    /// A clean in-plane rotation through `turns` physical turns, `n` samples, fed live. Returns the
    /// final spinor state. The director steps are well under Nyquist and elongation is high.
    fn rotate(turns: f32, n: usize) -> OrientationSpinor {
        let mut sp = OrientationSpinor::new();
        for k in 0..n {
            let frac = k as f32 / (n - 1) as f32;
            let phi = turns * 2.0 * PI * frac; // physical angle
            // The silhouette director is the physical angle folded mod-pi into [-pi/2, pi/2].
            let theta = wrap_pi2(phi); // headless: phi and phi+pi are identical
            sp.observe(theta, 6.0);
        }
        sp
    }

    #[test]
    fn lift_unwrap_recovers_winding() {
        // One physical turn -> director winds once, observable winds twice.
        let sp = rotate(1.0, 200);
        assert!(sp.orientation_reliable, "slow clean turn must stay reliable");
        assert!((sp.director_winding() - 1.0).abs() < 0.05, "W_dir ~ 1, got {}", sp.director_winding());
        assert!((sp.observable_winding() - 2.0).abs() < 0.05, "W_u ~ 2, got {}", sp.observable_winding());
    }

    #[test]
    fn sheet_flips_at_2pi_returns_at_4pi() {
        // Two physical turns: sheet must flip at 2pi and return at 4pi.
        let sp = rotate(2.0, 400);
        let a = sp.audit();
        assert_eq!(a.sheet_at_2pi, Some(-1), "sheet flips at 2pi");
        assert_eq!(a.sheet_at_4pi, Some(1), "sheet returns at 4pi");
        assert_eq!(a.verdict, SpinorVerdict::Accept, "clean double turn -> accept; note: {}", a.note);
    }

    #[test]
    fn one_turn_accepts_with_flip() {
        // A single physical turn: W_u=2 (even), W_dir=1, sheet flipped (odd parity) -> accept.
        let sp = rotate(1.0, 200);
        let a = sp.audit();
        assert_eq!(a.verdict, SpinorVerdict::Accept, "note: {}", a.note);
        assert_eq!(a.sheet_at_2pi, Some(-1));
        // The sheet is flipped relative to origin after exactly one turn (parity odd).
        assert_eq!(sp.sheet, -1);
    }

    #[test]
    fn aliasing_abstains() {
        // The director is mod-pi, so a *folded* step is always <= pi/2 by construction; aliasing is
        // exactly the regime where the TRUE per-frame director step approaches/exceeds pi/2 (the
        // fold then picks the wrong branch). Construct directors whose successive minimal-step is at
        // the Nyquist boundary: ~88 deg per frame trips the guard. This is what a too-fast rotation
        // (turn faster than ~2*fps/pi) looks like in the mod-pi samples — docs §1.2.
        let mut sp = OrientationSpinor::new();
        let step = NYQUIST; // a true pi/2 per-frame director step sits exactly on the guard
        for k in 0..40 {
            // raw director advances by `step` each frame, then is observed mod-pi.
            let theta = wrap_pi2(k as f32 * step);
            sp.observe(theta, 6.0);
        }
        assert!(!sp.orientation_reliable, "Nyquist-boundary director steps must mark unreliable");
        assert_eq!(sp.audit().verdict, SpinorVerdict::Abstain);
    }

    #[test]
    fn low_elongation_abstains() {
        // Round/blobby silhouette: axis ill-defined -> abstain even if the lift would be fine.
        let mut sp = OrientationSpinor::new();
        for k in 0..200 {
            let frac = k as f32 / 199.0;
            let phi = 1.0 * 2.0 * PI * frac;
            sp.observe(wrap_pi2(phi), 1.2); // below the reliable floor
        }
        assert!(!sp.orientation_reliable);
        assert_eq!(sp.audit().verdict, SpinorVerdict::Abstain);
    }

    #[test]
    fn wrap_pi2_is_minimal() {
        // Steps fold into (-pi/2, pi/2].
        assert!((wrap_pi2(0.1) - 0.1).abs() < 1e-6);
        assert!((wrap_pi2(PI - 0.1) - (-0.1)).abs() < 1e-5);
        assert!((wrap_pi2(-PI + 0.1) - 0.1).abs() < 1e-5);
    }
}
